import heapq


class EventManager:
    def __init__(self, events):
        self.priority = {}
        self.heap = []
        for eventId, prio in events:
            self.priority[eventId] = prio
            heapq.heappush(self.heap, (-prio, eventId))

    def updatePriority(self, eventId, newPriority):
        self.priority[eventId] = newPriority
        heapq.heappush(self.heap, (-newPriority, eventId))

    def pollHighest(self):
        while self.heap:
            negp, eventId = heapq.heappop(self.heap)
            if eventId in self.priority and self.priority[eventId] == -negp:
                del self.priority[eventId]
                return eventId
        return -1

