class EventManager {
    constructor(events) {
        this.priority = new Map();
        this.heap = [];
        for (const [eventId, prio] of events) {
            this.priority.set(eventId, prio);
            this._push(prio, eventId);
        }
    }
    _better(a, b) {
        if (a[0] !== b[0]) return a[0] > b[0];
        return a[1] < b[1];
    }
    _push(priority, eventId) {
        const heap = this.heap;
        heap.push([priority, eventId]);
        let i = heap.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (this._better(heap[i], heap[p])) {
                [heap[i], heap[p]] = [heap[p], heap[i]];
                i = p;
            } else break;
        }
    }
    _pop() {
        const heap = this.heap;
        const top = heap[0];
        const last = heap.pop();
        if (heap.length > 0) {
            heap[0] = last;
            let i = 0;
            while (true) {
                let best = i;
                const l = 2 * i + 1;
                const r = 2 * i + 2;
                if (l < heap.length && this._better(heap[l], heap[best])) best = l;
                if (r < heap.length && this._better(heap[r], heap[best])) best = r;
                if (best === i) break;
                [heap[i], heap[best]] = [heap[best], heap[i]];
                i = best;
            }
        }
        return top;
    }
    updatePriority(eventId, newPriority) {
        this.priority.set(eventId, newPriority);
        this._push(newPriority, eventId);
    }
    pollHighest() {
        while (this.heap.length > 0) {
            const [p, eventId] = this._pop();
            if (this.priority.has(eventId) && this.priority.get(eventId) === p) {
                this.priority.delete(eventId);
                return eventId;
            }
        }
        return -1;
    }
}
